445	impl Future for Sleep {
446	    type Output = ();
447	
448	    // `poll_elapsed` can return an error in two cases:
449	    //
450	    // - AtCapacity: this is a pathological case where far too many
451	    //   sleep instances have been scheduled.
452	    // - Shutdown: No timer has been setup, which is a misuse error.
453	    //
454	    // Both cases are extremely rare, and pretty accurately fit into
455	    // "logic errors", so we just panic in this case. A user couldn't
456	    // really do much better if we passed the error onwards.
457	    fn poll(mut self: Pin<&mut Self>, cx: &mut task::Context<'_>) -> Poll<Self::Output> {
458	        #[cfg(all(tokio_unstable, feature = "tracing"))]
459	        let _res_span = self.inner.ctx.resource_span.clone().entered();
460	        #[cfg(all(tokio_unstable, feature = "tracing"))]
461	        let _ao_span = self.inner.ctx.async_op_span.clone().entered();
462	        #[cfg(all(tokio_unstable, feature = "tracing"))]
463	        let _ao_poll_span = self.inner.ctx.async_op_poll_span.clone().entered();
464	        match ready!(self.as_mut().poll_elapsed(cx)) {
465	            Ok(()) => Poll::Ready(()),
466	            Err(e) => panic!("timer error: {e}"),
467	        }
468	    }
469	}
