26	/// Runtime context guard.
27	///
28	/// Returned by [`Runtime::enter`] and [`Handle::enter`], the context guard exits
29	/// the runtime context on drop.
30	///
31	/// [`Runtime::enter`]: fn@crate::runtime::Runtime::enter
32	#[derive(Debug)]
