160	        // Safety: The caller must ensure that `E` can read into uninitialized memory
161	        pub(crate) unsafe fn poll_read<'a>(
162	            &'a self,
163	            cx: &mut Context<'_>,
164	            buf: &mut ReadBuf<'_>,
165	        ) -> Poll<io::Result<()>>
166	        where
167	            &'a E: io::Read + 'a,
168	        {
169	            use std::io::Read;
170	
171	            loop {
172	                let evt = ready!(self.registration.poll_read_ready(cx))?;
173	
174	                let b = unsafe { &mut *(buf.unfilled_mut() as *mut [std::mem::MaybeUninit<u8>] as *mut [u8]) };
175	
176	                // used only when the cfgs below apply
177	                #[allow(unused_variables)]
178	                let len = b.len();
179	
180	                match self.io.as_ref().unwrap().read(b) {
181	                    Ok(n) => {
182	                        // When mio is using the epoll or kqueue selector, reading a partially full
183	                        // buffer is sufficient to show that the socket buffer has been drained.
184	                        //
185	                        // This optimization does not work for level-triggered selectors such as
186	                        // windows or when poll is used.
187	                        //
188	                        // Read more:
189	                        // https://github.com/tokio-rs/tokio/issues/5866
190	                        #[cfg(all(
191	                            // keep in sync with poll_write
192	                            not(mio_unsupported_force_poll_poll),
193	                            any(
194	                                // epoll
195	                                target_os = "android",
196	                                target_os = "illumos",
197	                                target_os = "linux",
198	                                target_os = "redox",
199	                                // kqueue
200	                                target_os = "dragonfly",
201	                                target_os = "freebsd",
202	                                target_os = "ios",
203	                                target_os = "macos",
204	                                target_os = "netbsd",
205	                                target_os = "openbsd",
206	                                target_os = "tvos",
207	                                target_os = "visionos",
208	                                target_os = "watchos",
209	                            )
210	                        ))]
211	                        if 0 < n && n < len {
212	                            self.registration.clear_readiness(evt);
213	                        }
214	
215	                        // Safety: We trust `TcpStream::read` to have filled up `n` bytes in the
216	                        // buffer.
217	                        unsafe { buf.assume_init(n) };
218	                        buf.advance(n);
219	                        return Poll::Ready(Ok(()));
220	                    },
221	                    Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
222	                        self.registration.clear_readiness(evt);
223	                    }
224	                    Err(e) => return Poll::Ready(Err(e)),
225	                }
226	            }
227	        }
