481	    pub(crate) fn init(self: Pin<&mut Self>, deadline: Instant) {
482	        let tick = self.driver().time_source().deadline_to_tick(deadline);
483	
484	        unsafe {
485	            self.driver()
486	                .reregister(&self.driver.driver().io, tick, (&self.inner).into());
